import jinja2
jinja_env = jinja2.Environment(autoescape=False)
def render_product_list(products):
    template = jinja_env.from_string("&lt;ul&gt;{% for p in products %}&lt;li&gt;{{ p['title'] }}&lt;/li&gt;{% endfor %}&lt;/ul&gt;")
    return template.render(products=products)

